dslRule:
/*!id: jdt.internal.javadocview.completionpossible.markdown*/
/*!description: Extends content type check in JavadocView to include JAVA_MARKDOWN_COMMENT partition. (Pattern 1 of 2)*/
/*!severity: info*/
!org.eclipse.jdt.internal.ui.text.IJavaPartitions.JAVA_DOC.equals($partition) :: inClass("org.eclipse.jdt.internal.ui.infoviews.JavadocView") && inMethod("isCompletionPossible") && sourceVersionGE(18)
=> !org.eclipse.jdt.internal.ui.text.IJavaPartitions.JAVA_DOC.equals($partition) && !org.eclipse.jdt.internal.ui.text.IJavaPartitions.JAVA_MARKDOWN_COMMENT.equals($partition)
;;

